@yzwik 很抱歉这么晚回复。

根据我的实验，分别使用illust和manga应当可以获得这个作者（1566167）的所有作品。

这是我的实验代码，最终输出为84个作品，与网页端看到的一样。

```python
from pixivpy3 import AppPixivAPI

username = 'username'
password = 'password '

user_id = 1566167


def get_imageUrls(aapi, pid, illust_type='illust'):
    json_result = aapi.user_illusts(pid, type=illust_type)
    while 1:
        try:
            nLen = len(json_result.illusts)
        except Exception as e:
            break
        for illust in json_result.illusts:
            yield illust

            if illust.page_count == 1 and illust.type != 'ugoira':
                print(illust.meta_single_page.original_image_url)
            elif illust.page_count > 1:
                image_urls = [
                    page.image_urls.original
                    for page in illust.meta_pages
                ]
                print(image_urls)
            else:
                image_urls = []
        try:
            next_qs = aapi.parse_qs(json_result.next_url)
            json_result = aapi.user_illusts(**next_qs)
        except Exception as e:
            break
    return 1


def main():
    aapi = AppPixivAPI()
    aapi.login(username, password)

    illust_ids = set()
    for illust in get_imageUrls(aapi, user_id, 'illust'):
        illust_ids.add(illust.id)
    for illust in get_imageUrls(aapi, user_id, 'manga'):
        illust_ids.add(illust.id)

    print(len(illust_ids))


if __name__ == '__main__':
    main()
```

As people answered in Stack Overflow, a simple, if not very clean solution, would be return a new type not derived from `tensor`, but containing a `const tensor&`. How does this sound to you?

```c++
struct const_tensor_holder {
    /* Maybe make it private and add a get() method? */
    const alias_tensor_instance &t;
};

const_tensor_holder operator() (
            const tensor& t,
            size_t offset
        );
```

