I noticed that the eventhandler are gone after one usage. So I helped myself with adding them via a scheduler task. I dont like this solution, but since I do need that "click" functionality (so it saves how many stars where clicked into a input field (which is in a form) I really dont see an alternative way.

```
//thx https://www.jqueryscript.net/other/Input-Field-Star-Rating-Plugin-jQuery.html

$(document).ready(function () {
    $.fn.extend({
        rating: function (options) {
            if (typeof(options) == 'undefined') options = {};
            let ratings = [];
            objs = this;
            if (objs.length) {
                for (let i = 0; i < objs.length; i++) {
                    ratings.push(new simpleRating(options, objs[i]));
                }
            }
        },
    });


    var Scheduler = (function () {
        var tasks = [];
        var minimum = 10;
        var timeoutVar = null;
        var output = {
            add: function (func, context, timer, once) {
                var iTimer = parseInt(timer);
                context = context && typeof context === 'object' ? context : null;
                if(typeof func === 'function' && !isNaN(iTimer) && iTimer > 0) {
                    tasks.push([func, context, iTimer, iTimer * minimum, once]);
                }
            },
            remove: function (func, context) {
                for(var i=0, l=tasks.length; i<l; i++) {
                    if(tasks[i][0] === func && (tasks[i][1] === context || tasks[i][1] == null)) {
                        tasks.splice(i, 1);
                        return;
                    }
                }
            },
            halt: function () {
                if(timeoutVar) {
                    clearInterval(timeoutVar);
                }
            }
        };
        var schedule = function () {
            for(var i=0, l=tasks.length; i<l; i++) {
                if(tasks[i] instanceof Array) {
                    tasks[i][3] -= minimum;
                    if(tasks[i][3] < 0) {
                        tasks[i][3] = tasks[i][2] * minimum;
                        tasks[i][0].apply(tasks[i][1]);
                        if(tasks[i][4]) {
                            tasks.splice(i, 1);
                        }
                    }
                }
            }
        };
        timeoutVar = setInterval(schedule, minimum);
        return output;
    })();

    class simpleRating {
        constructor(options, obj) {
            this.obj = obj;
            this.options = options;
            this.rating = 0;
            this.init();
        }

        bla() {
            $(window.simpleRatingObject).next().children().on('click', null, {classObj: window.simpleRatingInstance}, function (e) {
                e.data.classObj.rate(this);
            });

            $(window.simpleRatingObject).next().children().on('mouseenter', null, {classObj: window.simpleRatingInstance}, function (e) {
                e.data.classObj.setstars($(this).data('rating'));
            });

            $(window.simpleRatingObject).next().children().on('mouseleave', null, {classObj: window.simpleRatingInstance}, function (e) {
                e.data.classObj.setstars(e.data.classObj.rating);
            });
        }

        init() {
            let html = '<div class="simple-rating star-rating">';
            for (let i = 0; i < 5; i++) {
                html += '<i class="fal fa-star" data-rating="' + (i + 1) + '"></i>';
            }
            html += '</div>';

            $(this.obj)
                .attr('type', 'hidden')
                .after(html);

            window.simpleRatingObject = this.obj;
            window.simpleRatingInstance = this;


            Scheduler.add(this.bla, null, 11, false)
        }

        rate(obj) {
            let rating = $(obj).data('rating');
            $(obj).parent().prev().val(rating);
            this.rating = rating;
            this.refresh();
        }

        refresh() {
            this.setstars(this.rating);
        }

        setstars(rating) {
            for (let i = 0; i < 5; i++) {
                let $starObj = $(window.simpleRatingObject).next().children()[i];
                if (i < rating) {
                    $($starObj).attr('data-prefix', 'fas');
                } else {
                    $($starObj).attr('data-prefix', 'fal');
                }
            }
        }
    }
});
```

